class MemoryStore:
    def __init__(self):
        self.store = {}
        self.timestamps = {}

    def write(self, key: str, value: str, timestamp: float):
        # Check if new write is more recent
        if key not in self.timestamps or timestamp > self.timestamps[key]:
            self.store[key] = value
            self.timestamps[key] = timestamp
        else:
            # Conflict: older write; discard
            print(f"Conflict: Discarding older write for {key}")

# trust_resolver.py
class TrustResolver:
    def __init__(self):
        self.store = {}  # key -> (value, agent_id, trust_score)

    def write(self, key: str, value: str, agent_id: str, trust_score: float):
        if key not in self.store:
            # No conflict; store directly
            self.store[key] = (value, agent_id, trust_score)
        else:
            existing_value, existing_agent_id, existing_trust = self.store[key]

            if trust_score > existing_trust:
                # Higher trust wins
                self.store[key] = (value, agent_id, trust_score)
            else:
                # Lower trust; discard
                print(f"Conflict: Lower-trust agent {agent_id} lost to {existing_agent_id}")

