class BranchMerger:
    def __init__(self):
        self.branches = {}  # agent_id -> branch
        self.main = {}  # main branch

    def write(self, agent_id: str, key: str, value: str):
        # Write to agent's branch
        if agent_id not in self.branches:
            self.branches[agent_id] = {}
        self.branches[agent_id][key] = value

    def merge(self, agent_id: str):
        # Check for conflicts
        branch = self.branches[agent_id]
        for key, value in branch.items():
            if key in self.main and self.main[key] != value:
                # Conflict: require human review
                print(f"Conflict: {key} has different values in main ({self.main[key]}) and branch ({value})")
                request_human_review(key, self.main[key], value)
            else:
                # No conflict; merge
                self.main[key] = value

# event_sourcing.py
class EventStore:
    def __init__(self):
        self.events = []  # append-only log

    def write(self, key: str, value: str, agent_id: str, timestamp: float):
        # Append event (no conflict)
        self.events.append({
            "key": key,
            "value": value,
            "agent_id": agent_id,
            "timestamp": timestamp
        })

    def reconcile(self, key: str):
        # Reconcile: find latest event for this key
        events = [e for e in self.events if e["key"] == key]
        latest = max(events, key=lambda e: e["timestamp"])
        return latest["value"]

