import redis

r = redis.Redis(host="localhost", port=6379)

class TrustResolver:
    def write(self, key: str, value: str, agent_id: str, trust_score: float):
        # Check existing trust score
        existing = r.hgetall(f"memory:{key}")

        if not existing:
            # No conflict; store directly
            r.hset(f"memory:{key}", mapping={"value": value, "agent_id": agent_id, "trust": trust_score})
        else:
            existing_trust = float(existing["trust"])

            if trust_score > existing_trust:
                # Higher trust wins
                r.hset(f"memory:{key}", mapping={"value": value, "agent_id": agent_id, "trust": trust_score})
            else:
                # Lower trust; discard
                raise ConflictError(f"Conflict: Lower-trust agent {agent_id} lost to {existing['agent_id']}")

# event_store.py
class EventStore:
    def __init__(self):
        self.events = []

    def write(self, key: str, value: str, agent_id: str):
        # Append event (no conflict)
        self.events.append({
            "key": key,
            "value": value,
            "agent_id": agent_id,
            "timestamp": time.time()
        })

    def reconcile(self, key: str):
        # Reconcile: find latest event
        events = [e for e in self.events if e["key"] == key]
        if not events:
            return None
        latest = max(events, key=lambda e: e["timestamp"])
        return latest["value"]
